1	export type Cell = [number, number];
2	
3	const isNeighbor = ([ax, ay]: Cell, [bx, by]: Cell): boolean =>
4	  (ax !== bx || ay !== by) && Math.abs(ax - bx) <= 1 && Math.abs(ay - by) <= 1;
5	
6	const countLiveNeighbors = (cell: Cell, cells: Cell[]): number =>
7	  cells.filter((other) => isNeighbor(cell, other)).length;
